if self.vec.len() == self.orig_len {
    // We must not have produced, so just call a normal drain to remove the items.
    self.vec.drain(start..end);
} else if start == end {
    // Empty range, so just restore the length to its original state
    unsafe {
        self.vec.set_len(self.orig_len);
    }
} else if end < self.orig_len {
    // The producer was responsible for consuming the drained items.
    // Move the tail items to their new place, then set the length to include them.
    unsafe {
        let ptr = self.vec.as_mut_ptr().add(start);
        let tail_ptr = self.vec.as_ptr().add(end);
        let tail_len = self.orig_len - end;
        ptr::copy(tail_ptr, ptr, tail_len);
        self.vec.set_len(start + tail_len);
    }
}

if let Some(metadata_vec) = build_runner.find_build_script_metadatas(unit) {
    for metadata in metadata_vec {
        if let Some(output) = build_runner
            .build_script_outputs
            .lock()
            .unwrap()
            .get(metadata)
        {
            for path in &output.rerun_if_changed {
                let package_root = unit.pkg.root();

                let path = if path.as_os_str().is_empty() {
                    // Joining with an empty path causes Rust to add a trailing path separator.
                    // On Windows, this would add an invalid trailing backslash to the .d file.
                    package_root.to_path_buf()
                } else {
                    // The paths we have saved from the unit are of arbitrary relativeness and
                    // may be relative to the crate root of the dependency.
                    package_root.join(path)
                };

                deps.insert(path);
            }
        }
    }
}

