for (lint_name, &lint_span) in &self.declared_lints {
    // When using the `declare_tool_lint!` macro, the original `lint_span`'s
    // file points to "<rustc macros>".
    // `compiletest-rs` thinks that's an error in a different file and
    // just ignores it. This causes the test in compile-fail/lint_pass
    // not able to capture the error.
    // Therefore, we need to climb the macro expansion tree and find the
    // actual span that invoked `declare_tool_lint!`:
    let lint_span = lint_span.ctxt().outer_expn_data().call_site;

    if !self.registered_lints.contains(lint_name) {
        span_lint(
            cx,
            LINT_WITHOUT_LINT_PASS,
            lint_span,
            format!("the lint `{lint_name}` is not added to any `LintPass`"),
        );
    }
}

if let Some(existing) =
            self.def_path_hash_to_index.insert(&local_hash, &def_id.local_def_index)
        {
            let def_path1 = self.def_path(LocalDefId { local_def_index: existing });
            let def_path2 = self.def_path(def_id);

            // Continuing with colliding DefPathHashes can lead to correctness
            // issues. We must abort compilation.
            //
            // The likelihood of such a collision is very small, so actually
            // running into one could be indicative of a poor hash function
            // being used.
            //
            // See the documentation for DefPathHash for more information.
            panic!(
                "found DefPathHash collision between {def_path1:#?} and {def_path2:#?}. \
                    Compilation cannot continue."
            );
        }

if parser_replacements_start == parser_replacements_end
            && inner_attr_parser_replacements.is_empty()
        {
            ThinVec::new()
        } else {
            // Grab any replace ranges that occur *inside* the current AST node. Convert them
            // from `ParserRange` form to `NodeRange` form. We will perform the actual
            // replacement only when we convert the `LazyAttrTokenStream` to an
            // `AttrTokenStream`.
            self.capture_state.parser_replacements
                [parser_replacements_start..parser_replacements_end]
                .iter()
                .cloned()
                .chain(inner_attr_parser_replacements)
                .map(|(parser_range, data)| {
                    (NodeRange::new(parser_range, collect_pos.start_pos), data)
                })
                .collect()
        }

if let Some(ty) = self.state.cur_ty.builtin_deref(self.include_raw_pointers) {
    debug_assert_eq!(ty, self.infcx().resolve_vars_if_possible(ty));
    // NOTE: we may still need to normalize the built-in deref in case
    // we have some type like `&<Ty as Trait>::Assoc`, since users of
    // autoderef expect this type to have been structurally normalized.
    if let TyKind::Alias(..) = ty.kind() {
        let (normalized_ty, obligations) =
            structurally_normalize_ty(self.infcx(), self.param_env(), ty, self.span)?;
        self.state.obligations.extend(obligations);
        (AutoderefKind::Builtin, normalized_ty)
    } else {
        (AutoderefKind::Builtin, ty)
    }
} else if let Some(ty) = self.overloaded_deref_ty(self.state.cur_ty) {
    // The overloaded deref check already normalizes the pointee type.
    (AutoderefKind::Overloaded, ty)
} else {
    return None;
}

match parent_expr.kind {
    ExprKind::MethodCall(segment, recv, ..)
        // We currently only lint `str` methods (which `String` can deref to), so a `.is_str()` check is sufficient here
        // (contrary to the `ExprKind::Index` case which needs to handle both with `is_string_like` because `String` implements
        // `Index` directly and no deref to `str` would happen in that case).
        if cx.typeck_results().expr_ty_adjusted(recv).peel_refs().is_str()
            && BYTE_INDEX_METHODS.contains(&segment.ident.name)
            && eq_expr_value(cx, expr.span.ctxt(), chars_recv, recv) =>
    {
        "passing a character position to a method that expects a byte index"
    },
    ExprKind::Index(target, ..)
        if is_string_like(cx.typeck_results().expr_ty_adjusted(target).peel_refs())
            && eq_expr_value(cx, expr.span.ctxt(), chars_recv, target) =>
    {
        "indexing into a string with a character position where a byte index is expected"
    },
    _ => return,
}

loop {
    let head = self.inner.head.load(Acquire);
    let (steal, real) = unpack(head);

    // safety: this is the **only** thread that updates this cell.
    let tail = unsafe { self.inner.tail.unsync_load() };

    if tail.wrapping_sub(steal) < LOCAL_QUEUE_CAPACITY as UnsignedShort {
        // There is capacity for the task
        break tail;
    } else if steal != real {
        // Concurrently stealing, this will free up capacity, so only
        // push the task onto the inject queue
        overflow.push(task);
        return;
    } else {
        // Push the current task and half of the queue into the
        // inject queue.
        match self.push_overflow(task, real, tail, overflow, stats) {
            Ok(_) => return,
            // Lost the race, try again
            Err(v) => {
                task = v;
            }
        }
    }
}

if snapshot.is_cancelled() || snapshot.is_complete() {
    // Aborts to completed or cancelled tasks are no-ops.
    (false, None)
} else if snapshot.is_running() {
    // If the task is running, we mark it as cancelled. The thread
    // running the task will notice the cancelled bit when it
    // stops polling and it will kill the task.
    //
    // The set_notified() call is not strictly necessary but it will
    // in some cases let a wake_by_ref call return without having
    // to perform a compare_exchange.
    snapshot.set_notified();
    snapshot.set_cancelled();
    (false, Some(snapshot))
} else {
    // The task is idle. We set the cancelled and notified bits and
    // submit a notification if the notified bit was not already
    // set.
    snapshot.set_cancelled();
    if !snapshot.is_notified() {
        snapshot.set_notified();
        snapshot.ref_inc();
        (true, Some(snapshot))
    } else {
        (false, Some(snapshot))
    }
}

match self.state.compare_exchange(EMPTY, PARKED, SeqCst, SeqCst) {
    Ok(_) => {}
    Err(NOTIFIED) => {
        // We must read here, even though we know it will be `NOTIFIED`.
        // This is because `unpark` may have been called again since we read
        // `NOTIFIED` in the `compare_exchange` above. We must perform an
        // acquire operation that synchronizes with that `unpark` to observe
        // any writes it made before the call to unpark. To do that we must
        // read from the write it made to `state`.
        let old = self.state.swap(EMPTY, SeqCst);
        debug_assert_eq!(old, NOTIFIED, "park state changed unexpectedly");

        return;
    }
    Err(actual) => panic!("inconsistent park state; actual = {actual}"),
}

match self
            .state
            .compare_exchange(EMPTY, PARKED_CONDVAR, SeqCst, SeqCst)
        {
            Ok(_) => {}
            Err(NOTIFIED) => {
                // We must read here, even though we know it will be `NOTIFIED`.
                // This is because `unpark` may have been called again since we read
                // `NOTIFIED` in the `compare_exchange` above. We must perform an
                // acquire operation that synchronizes with that `unpark` to observe
                // any writes it made before the call to unpark. To do that we must
                // read from the write it made to `state`.
                let old = self.state.swap(EMPTY, SeqCst);
                debug_assert_eq!(old, NOTIFIED, "park state changed unexpectedly");

                return;
            }
            Err(actual) => panic!("inconsistent park state; actual = {actual}"),
        }

for global_arg in global_arg_vec {
    if let Some(ma) = self.get(global_arg) {
        // We have to check if the parent's global arg wasn't used but still exists
        // such as from a default value.
        //
        // For example, `myprog subcommand --global-arg=value` where `--global-arg` defines
        // a default value of `other` myprog would have an existing MatchedArg for
        // `--global-arg` where the value is `other`
        let to_update = if let Some(parent_ma) = vals_map.get(global_arg) {
            if parent_ma.source() > ma.source() {
                parent_ma
            } else {
                ma
            }
        } else {
            ma
        }
        .clone();
        vals_map.insert(global_arg.clone(), to_update);
    }
}

for local in self.locals.iter(guard) {
    match local {
        Err(IterError::Stalled) => {
            // A concurrent thread stalled this iteration. That thread might also try to
            // advance the epoch, in which case we leave the job to it. Otherwise, the
            // epoch will not be advanced.
            return global_epoch;
        }
        Ok(local) => {
            let local_epoch = local.epoch.load(Ordering::Relaxed);

            // If the participant was pinned in a different epoch, we cannot advance the
            // global epoch just yet.
            if local_epoch.is_pinned() && local_epoch.unpinned() != global_epoch {
                return global_epoch;
            }

            #[cfg(crossbeam_sanitize_thread)]
            locals.push(local);
        }
    }
}

if value.head.get_mut() != value.tail.get_mut() {
    let index = head & (value.one_lap - 1);
    let lap = head & !(value.one_lap - 1);
    // SAFETY: We have mutable access to this, so we can read without
    // worrying about concurrency. Furthermore, we know this is
    // initialized because it is the value pointed at by `value.head`
    // and this is a non-empty queue.
    let val = unsafe {
        debug_assert!(index < value.buffer.len());
        let slot = value.buffer.get_unchecked_mut(index);
        slot.value.get().read().assume_init()
    };
    let new = if index + 1 < value.capacity() {
        // Same lap, incremented index.
        // Set to `{ lap: lap, index: index + 1 }`.
        head + 1
    } else {
        // One lap forward, index wraps around to zero.
        // Set to `{ lap: lap.wrapping_add(1), index: 0 }`.
        lap.wrapping_add(value.one_lap)
    };
    *value.head.get_mut() = new;
    Some(val)
} else {
    None
}

match self.state.compare_exchange(EMPTY, PARKED, SeqCst, SeqCst) {
    Ok(_) => {}
    // Consume this notification to avoid spurious wakeups in the next park.
    Err(NOTIFIED) => {
        // We must read `state` here, even though we know it will be `NOTIFIED`. This is
        // because `unpark` may have been called again since we read `NOTIFIED` in the
        // `compare_exchange` above. We must perform an acquire operation that synchronizes
        // with that `unpark` to observe any writes it made before the call to `unpark`. To
        // do that we must read from the write it made to `state`.
        let old = self.state.swap(EMPTY, SeqCst);
        assert_eq!(old, NOTIFIED, "park state changed unexpectedly");
        return UnparkReason::Unparked;
    }
    Err(n) => panic!("inconsistent park_timeout state: {}", n),
}

match head_rc.as_ref().map(RcRef::split) {
  Some((head, rc)) => {
    // Register this `Cancelable` node with a `CancelHandle` head node.
    assert_ne!(self, head);
    let self_inner = NonNull::new(self.inner.get()).unwrap();
    let head_inner = NonNull::new(head.inner.get()).unwrap();
    NodeInner::link(self_inner, waker, head_inner, rc)
  }
  None => {
    // This `Cancelable` has already been linked to a `CancelHandle` head
    // node; just update our stored `Waker` if necessary.
    // TODO(piscisaureus): safety comment
    #[allow(
      clippy::undocumented_unsafe_blocks,
      reason = "safety comment on the containing block"
    )]
    let inner = unsafe { &mut *self.inner.get() };
    inner.update_waker(waker)
  }
}

if let Some(changed_paths) = changed_paths
        {
          let changed_paths = changed_paths.into_iter().collect::<HashSet<_>>();
          // If an env file changed, reload all bench modules since any
          // bench could depend on environment variables.
          let env_file_changed = cli_options
            .possible_env_file_paths_for_watch()
            .any(|path| changed_paths.contains(&path));
          if env_file_changed {
            bench_modules.clone()
          } else {
            let mut result = IndexSet::with_capacity(bench_modules.len());
            for bench_module_specifier in bench_modules {
              if has_graph_root_local_dependent_changed(
                &graph,
                bench_module_specifier,
                &changed_paths,
              ) {
                result.insert(bench_module_specifier.clone());
              }
            }
            result
          }
        } else {
          bench_modules.clone()
        }

if let Some(path) = output_path {
  let p = PathBuf::from(path);
  if p.components().any(|c| c == std::path::Component::ParentDir) {
    log::warn!("Output path '{}' contains '..' components", path);
  }
  p
} else {
  // Convert @scope/name to scope-name
  let normalized = name.replace('@', "").replace('/', "-");
  // The package name shape is checked against `@scope/name` higher up
  // (see `pack` in mod.rs), but that check is loose — it does not
  // forbid path-traversal sequences. Treat this as a hard safety
  // boundary right before we open a file, rejecting any derived
  // tarball name that contains `..` or path separators so we never
  // escape the cwd regardless of upstream validation drift.
  if normalized.contains("..") || normalized.contains('/') {
    return Err(deno_core::anyhow::anyhow!(
      "refusing to write tarball with unsafe name derived from package: {}",
      name
    ));
  }
  PathBuf::from(format!("{}-{}.tgz", normalized, version))
}

match main_module_npm_ref {
  Some(package_ref) => {
    // use a fake referrer that can be used to discover the package.json if necessary
    let referrer = self.shared.initial_cwd.join("package.json")?;
    let package_folder =
      self.npm_resolver.resolve_pkg_folder_from_deno_module_req(
        package_ref.req(),
        &referrer,
      )?;
    let main_module =
      self.lib_main_worker_factory.resolve_npm_binary_entrypoint(
        &package_folder,
        package_ref.sub_path(),
      )?;

    if let Some(lockfile) = &self.maybe_lockfile {
      // For npm binary commands, ensure that the lockfile gets updated
      // so that we can re-use the npm resolution the next time it runs
      // for better performance
      lockfile.write_if_changed()?;
    }

    main_module
  }
  None => main_module,
}

match image_bitmap_source {
  ImageBitmapSource::Blob => {
    // Note: According to browser behavior and wpt results, if Exif contains image orientation,
    // it applies the rotation from it before following the value of imageOrientation.
    // This is not stated in the spec but in MDN currently.
    // https://github.com/mdn/content/pull/34366

    // SAFETY: The orientation is always Some if the image is from a Blob.
    let orientation = orientation.unwrap();
    DynamicImage::apply_orientation(&mut image, orientation);

    match image_orientation {
      ImageOrientation::FlipY => image.flipv(),
      ImageOrientation::FromImage => image,
    }
  }
  ImageBitmapSource::ImageData | ImageBitmapSource::ImageBitmap => {
    match image_orientation {
      ImageOrientation::FlipY => image.flipv(),
      ImageOrientation::FromImage => image,
    }
  }
}

if RESERVED_WORDS.contains(name) || !is_valid_var_decl(name) {
  *temp_var_count += 1;
  // we can't create an identifier with a reserved word or invalid identifier name,
  // so assign it to a temporary variable that won't have a conflict, then re-export
  // it as a string
  builder.append("const __deno_export_");
  builder.append(*temp_var_count);
  builder.append("__ = ");
  build_initializer(builder);
  builder.append(";\nexport { __deno_export_");
  builder.append(*temp_var_count);
  builder.append("__ as ");
  builder.append(quoted_name);
  builder.append(" };\n");
} else {
  builder.append("export const ");
  builder.append(name);
  builder.append(" = ");
  build_initializer(builder);
  builder.append(";\n");
}

for (package, package_path, extra) in &self.entries {
  if !filter(package) {
    continue;
  }
  if let Some(bin_entries) = &extra.bin {
    match bin_entries {
      deno_npm::registry::NpmPackageVersionBinEntry::String(script) => {
        let name = default_bin_name(package);
        if !seen.insert(name) {
          already_seen(self.sys, package_path, script)?;
          // we already set up a bin entry with this name
          continue;
        }
        new(self.sys, package, extra, package_path, name, script)?;
      }
      deno_npm::registry::NpmPackageVersionBinEntry::Map(entries) => {
        for (name, script) in entries {
          if !seen.insert(name) {
            already_seen(self.sys, package_path, script)?;
            // we already set up a bin entry with this name
            continue;
          }
          new(self.sys, package, extra, package_path, name, script)?;
        }
      }
    }
  }
}

if consumer.full() {
    consumer.into_folder().complete()
} else if splitter.try_split(migrated) {
    match producer.split() {
        (left_producer, Some(right_producer)) => {
            let (reducer, left_consumer, right_consumer) =
                (consumer.to_reducer(), consumer.split_off_left(), consumer);
            let bridge = bridge_unindexed_producer_consumer;
            let (left_result, right_result) = join_context(
                |context| bridge(context.migrated(), splitter, left_producer, left_consumer),
                |context| bridge(context.migrated(), splitter, right_producer, right_consumer),
            );
            reducer.reduce(left_result, right_result)
        }
        (producer, None) => producer.fold_with(consumer.into_folder()).complete(),
    }
} else {
    producer.fold_with(consumer.into_folder()).complete()
}

match &opts.features {
    // This returns `false` for CliFeatures just for simplicity. It
    // would take a bit of work to compare since they are not in the
    // same format as DepFeatures (and that may be expensive
    // performance-wise). Also, it should only occur once for a root
    // package. The only drawback is that it may re-activate a root
    // package again, which should only affect performance, but that
    // should be rare. Cycles should still be detected since those
    // will have `DepFeatures` edges.
    RequestedFeatures::CliFeatures(_) => Ok(false),
    RequestedFeatures::DepFeatures {
        features,
        uses_default_features,
    } => {
        let has_default_feature = summary.features().contains_key(&INTERNED_DEFAULT);
        let prev = self
            .resolve_features
            .get(&id)
            .map(|f| &**f)
            .unwrap_or(&empty_features);
        Ok(features.is_subset(prev)
            && (!uses_default_features
                || prev.contains(&INTERNED_DEFAULT)
                || !has_default_feature))
    }
}

if krate.is_placeholder {
    self.visit_macro_invoc(krate.id);
    self.visit_invoc_in_module(krate.id);
} else {
    // Visit attributes after items for backward compatibility.
    // This way they can use `macro_rules` defined later.

    // We always have an invocation parent (set in `collect_definitions`)
    // of at least the crate root, even for visiting the crate root,
    // which would then remove the crate root from the tables
    // list twice and try to insert it twice afterwards.
    debug_assert_eq!(self.r.current_owner.id, CRATE_NODE_ID);

    visit::walk_list!(self, visit_item, &krate.items);
    visit::walk_list!(self, visit_attribute, &krate.attrs);
    self.contains_macro_use(&krate.attrs);
}

if !self.tcx.next_trait_solver_globally() {
    // `OpaqueCast` projections are only needed if there are opaque types on which projections
    // are performed. After the `PostAnalysisNormalize` pass, all opaque types are replaced with their
    // hidden types, so we don't need these projections anymore.
    //
    // Performance optimization: don't reintern if there is no `OpaqueCast` to remove.
    if place.projection.iter().any(|elem| matches!(elem, ProjectionElem::OpaqueCast(_))) {
        place.projection = self.tcx.mk_place_elems(
            &place
                .projection
                .into_iter()
                .filter(|elem| !matches!(elem, ProjectionElem::OpaqueCast(_)))
                .collect::<Vec<_>>(),
        );
    };
}

if impls_default_trait && ends_of_record_list {
    // FIXME: This should make use of scope_def like completions so we get all the other goodies
    // that is we should handle this like actually completing the default function
    let completion_text = "..Default::default()";
    let mut item = CompletionItem::new(
        SymbolKind::Field,
        ctx.source_range(),
        SmolStr::new_static(completion_text),
        ctx.edition,
    );
    let completion_text =
        completion_text.strip_prefix(ctx.token.text()).unwrap_or(completion_text);
    item.insert_text(completion_text).set_relevance(CompletionRelevance {
        postfix_match: Some(CompletionRelevancePostfixMatch::Exact),
        ..Default::default()
    });
    item.add_to(acc, ctx.db);
}

if let Some(configuration) = self.configuration.borrow().as_ref() {
  self.texture_descriptor.replace(Some(
    self
      .get_descriptor_for_configuration(configuration)
      .unwrap(),
  ));

  match &self.data {
    ContextData::Canvas(_) => {}
    ContextData::Surface(surface_data) => {
      let texture_descriptor = self.texture_descriptor.borrow();

      let Descriptor::Surface(descriptor) =
        texture_descriptor.as_ref().unwrap()
      else {
        unreachable!()
      };

      let err = configuration.device.instance.surface_configure(
        surface_data.borrow().id,
        configuration.device.id,
        descriptor,
      );

      configuration.device.error_handler.push_error(err);
    }
  }
}

if args.is_present_with_zero_values("invert") {
    match &packages {
        Packages::Packages(ps) => {
            // Backwards compatibility with old syntax of `cargo tree -i -p foo`.
            invert.extend(ps.clone());
        }
        _ => {
            return Err(format_err!(
                r#"a package name is required for `-i` but none was supplied

note: `-p <spec> -i` is not supported; pass the package name to `-i` directly.

help: to inspect the reverse dependencies of a specific package, pass the name directly to `-i`:

cargo tree -i <spec>

help: if you are in a workspace and want to search across all members, use:

cargo tree --workspace -i <spec>
"#
            )
            .into());
        }
    }
}

if processes.is_empty() {
  message.push_str(
    "\n\nThis is usually an editor running the Deno language server holding \
     the cache open. Close it (or any running `deno` process) and run `deno \
     clean` again.",
  );
} else {
  message.push_str("\n\nHeld open by:");
  for process in processes {
    let label = match &process.exe {
      Some(exe) => exe.display().to_string(),
      None => process.name.clone(),
    };
    let hint = if process.is_deno {
      " (a running Deno process, likely the language server in your editor)"
    } else {
      ""
    };
    message.push_str(&format!("\n  {} (PID {}){}", label, process.pid, hint));
  }
  message
    .push_str("\n\nClose the process(es) above and run `deno clean` again.");
}

if generics.own_requires_monomorphization()
        // When an EII implementation is automatically generated by the `#[eii]` macro,
        // it will directly refer to the foreign item, not through a macro.
        // We don't want to emit this error if it's an implementation that's generated by the `#[eii]` macro,
        // since in that case it looks like a duplicate error: the declaration of the EII already can't contain generics.
        // So, we check here if at least one of the eii impls has ImplResolution::Macro, which indicates it's
        // not generated as part of the declaration.
        && find_attr!(tcx, external_impl, EiiImpls(impls) if impls.iter().any(|i| matches!(i.resolution, EiiImplResolution::Macro(_)))
        )
    {
        tcx.dcx().emit_err(EiiWithGenerics {
            span: tcx.def_span(external_impl),
            attr: eii_attr_span,
            eii_name,
            impl_name: tcx.item_name(external_impl),
        });
    }
